// Normaliza (saca tildes y pasa a minúsculas)
const normalize = (v = '') =>
  v.toString()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase();

const allowed = new Set([
  'usabilidad',
  'compatibilidad',
  'precio',
  'rendimiento',
  'diseno',
  'otro',
]);

// Tomá el tema desde donde realmente viene
const temaRaw =
  $json.tema_sugerencia ??
  $json.output?.tema_sugerencia ??
  $json.output?.label ??
  $json.output?.category ??
  'otro';

let tema = normalize(temaRaw);
if (!allowed.has(tema)) tema = 'otro';

// (opcional) sacá el objeto output para que Airtable no se confunda
const { output, ...rest } = $json;

return {
  json: {
    ...rest,
    tema_sugerencia: tema,
    categoria_ia: 'sugerencia',
    accion_ejecutada: 'Registrado para revisión de producto',
  },
};

