const base = $json;
const ia = (base.output && typeof base.output === "object") ? base.output : base;

const sentimiento = (ia.sentimiento ?? "").toString().trim();
const categoria = (ia.categoria ?? "").toString().trim();
const resumen_ia = (ia.resumen ?? "").toString().trim();
const accion_recomendada = (ia.accion_recomendada ?? "").toString().trim();

const allowedCat = new Set(["satisfaccion","sugerencia","observacion","falla_tecnica","reclamo"]);
const allowedSent = new Set(["positivo","neutro","negativo"]);

let estado = "procesado";
let observacion = "";
let camino = "";
let accion_ejecutada = "";

// Validación mínima
if (!allowedCat.has(categoria) || !allowedSent.has(sentimiento) || !resumen_ia || !accion_recomendada) {
  estado = "pendiente_revision";
  const faltantes = [];
  if (!allowedSent.has(sentimiento)) faltantes.push("sentimiento inválido/faltante");
  if (!allowedCat.has(categoria)) faltantes.push("categoria inválida/faltante");
  if (!resumen_ia) faltantes.push("resumen faltante");
  if (!accion_recomendada) faltantes.push("accion_recomendada faltante");

  observacion = `Salida IA inválida o incompleta: ${faltantes.join(", ")}.`;
  camino = "Revisión manual";
  accion_ejecutada = "Escalar a revisión";
} else {
  // Ruteo consistente con tu Switch
  if (categoria === "satisfaccion") {
    camino = "Clientes felices";
    accion_ejecutada = "Agradecimiento enviado";
  } else if (categoria === "sugerencia") {
    camino = "Ideas y mejoras";
    accion_ejecutada = "Registrado y categorizado (tema)";
  } else if (categoria === "observacion") {
    camino = "Experiencias neutrales";
    accion_ejecutada = "Registrado sin acción adicional";
  } else if (categoria === "falla_tecnica") {
    camino = "Casos técnicos";
    accion_ejecutada = "Ticket técnico creado y alerta enviada";
  } else if (categoria === "reclamo") {
    camino = "Reclamos";
    accion_ejecutada = "Reclamo registrado y alerta enviada";
  }
}

return [{
  json: {
    ...base,

    // Normalización estándar para el resto del flujo
    sentimiento,
    categoria,
    categoria_detectada: categoria,
    resumen_ia,
    accion_recomendada,

    estado,
    observacion,
    camino,
    accion_ejecutada,
  }
}];
